        firstPlayer--; secondPlayer--;
        int earliest = n, latest = 0;
        for (int mask = (1 << n) - 1; mask >= 0; mask--) {
            int players = 0, f = -1, s = -1;
            for (int i = 0; i < n; i++) {
                if ((mask >> i) & 1) {
                    if (i == firstPlayer) f = players;
                    if (i == secondPlayer) s = players;
                    players++;
                }
            }
            int round = 1;
