                        earliest = min(earliest, round);
                    }
                    if (f == i || f == players - 1 - i) {
                        mask &= ~(1 << (players - 1 - i));
                        new_players++;
                    } else if (s == i || s == players - 1 - i) {
                        mask &= ~(1 << i);
                        new_players++;
